#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    int is_leaf;
    int num_keys;
} knode;

__kernel void findK(
    const long maxheight,
    __global knode* knodes,
    const long knodes_elem,
    __global record* records,
    __global long* currKnode,
    __global long* offset,
    __global int* keys,
    __global record* ans,
    const int count,
    const int order)
{
    int global_id = get_global_id(0);
    int local_size = get_local_size(0);
    int bid = global_id / local_size;
    int thid = global_id % local_size;

    if (bid >= count) return;

    long curr = currKnode[bid];
    long off = offset[bid];
    int key = keys[bid];

    for (int i = 0; i < maxheight; i++) {
        barrier(CLK_LOCAL_MEM_FENCE);
        if (thid < order - 1) {
            int key_left = knodes[curr].keys[thid];
            int key_right = knodes[curr].keys[thid + 1];
            if (key_left <= key && key < key_right) {
                if (knodes_elem > knodes[off].indices[thid]) {
                    off = knodes[off].indices[thid];
                }
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        curr = off;
    }

    if (thid == 0) {
        currKnode[bid] = curr;
        offset[bid] = off;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (thid < order) {
        if (keys[bid] == knodes[curr].keys[thid]) {
            ans[bid].value = records[knodes[curr].indices[thid]].value;
        }
    }
}

